var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"누구냐, 너희들은.","JPN":"君たちは何者だ。","ENG":"Who art thou?","TWN":"報上名來！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"특이한 복장이로군. 이방인인가.","JPN":"変わった服装だな。異邦人か。","ENG":"What curious liveries you don. Be you outsiders to this land?","TWN":"穿那什麼奇裝異服，是外邦人嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어, 그게……","JPN":"ええと、それが……","ENG":"Err, well…","TWN":"呃，那個……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"숲에서 길을 잃고 헤매다 여기까지 오게 됐지 뭐예요.","JPN":"森で道に迷って、ここまで辿り着いてしまったんです。","ENG":"We got lost in the woods and ended up wandering here.","TWN":"我們在森林裡迷路了，走著走著就走到這裡了。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"죄송하지만 여기가 어딘지 알려 주실 수 있을까요?","JPN":"すみませんが、ここがどこなのか教えていただけませんか？","ENG":"Would you mind telling us where we are?","TWN":"不好意思，請問你知道這裡是哪裡嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"흠. 길을 잃었는데도 여기까지 오다니, 행운의 여신께서 도우셨나 보군.","JPN":"ふむ。迷子になってここまで来るとは。幸運の女神様のお恵みだな。","ENG":"Hmph. Thou hast lost thine heading yet hast wandered hither? Why, Lady Fortune smileth upon thee.","TWN":"呵，迷路還可以走到這裡來，看來幸運女神很眷顧你們！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"여긴 센트럴 팰리스다.","JPN":"ここはセントラルパレスだ。","ENG":"This is the Central Palace.","TWN":"這裡是聖特羅貝里斯，"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"아르카데나 제국의 수도이자, 인류의 마지막 보루지.","JPN":"アルカデナ帝国の首都であり、人類最後の砦である。","ENG":"The capital of the Empire of Arcadena, the final bastion of Man.","TWN":"就是艾爾卡特納帝國的首都，也是人類最後的堡壘。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"희한한 무기를 든 걸 보니 모험가인 모양이군. 맞나?","JPN":"珍しい武器を持っているということは、冒険者のようだな。違うか？","ENG":"Thy peculiar arms suggest thou earnest thy keep adventuring. Is that right?","TWN":"看你們手中拿著罕見的武器，你們是冒險家沒錯吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 하하. 맞아요, 모험가. 일거리를 찾으러 다니는 중이었어요.","JPN":"あ、はい、そうです。冒険者です、アハハ。仕事を探している途中だったんです。","ENG":"Oh... Haha... That's right. We're adventurers. Looking for a job.","TWN":"哦～哈哈，沒錯，我們正在找看看有沒有什麼事是可以做的。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"도시 남쪽의 상업 지구에 모험가 조합이 있다. 일거리를 찾는다면 그리로 가 보도록.","JPN":"町の南の商業地区に冒険者ギルドがある。仕事を探すならそこに行ってみるといい。","ENG":"The Adventurer's Guild lies at the southern commercial district of the city. Head there if ye seek work.","TWN":"在南邊的商業區有個冒險家協會，你們可去那裡打聽看看！"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"좋은 정보네요. 감사합니다.","JPN":"いい情報をありがとうございます。","ENG":"That's a great tip. Thank you.","TWN":"很棒的情報，謝謝你！"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"아, 그리고 한 가지 더.","JPN":"ああ、あともう一つ。","ENG":"Ah, one more thing.","TWN":"喔，還有一件事！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"최근 센트럴 팰리스는 마왕의 수하들에게 쫓겨 온 난민들로 매우 소란스럽다.","JPN":"近頃セントラルパレスは、魔王の部下に追いやられた難民たちで非常に騒々しい。","ENG":"Central Palace has fallen into tumult lately from the deluge of refugees fleeing the Demon Lord's minions.","TWN":"最近聖特羅貝里斯因為那些被魔王趕出來的難民治安非常糟糕。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그러니 괜히 문제를 일으키지 말고 얌전히 지내라.","JPN":"なので、余計な揉め事を起こさないよう静かに過ごしてくれ。","ENG":"So do not go about causing trouble here.","TWN":"我勸你們最好安分一點，不要惹事。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"모험가랍시고 치안을 어지럽혔다간 추방되거나 감옥에 갇히게 될 테니까.","JPN":"冒険者とはいえ治安を乱したら、追放か監獄に閉じ込められることになるぞ。","ENG":"Else, you shall find yourselves exiled... or worse, in fetters.","TWN":"滋事的話，輕則被流放，重則是要進監牢的！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"마왕…… 이라고요?","JPN":"魔王……ですか？","ENG":"Did you say… Demon Lord?","TWN":"魔王是……？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};